const activityItems=()=>{const base=(A||[]).map(x=>({kind:"bitacora",ts:dateVal(x.fecha||x.fecha_creacion||x.created_at),raw:x})).filter(x=>x.ts),up=D.slice(0,20).map(x=>({kind:"doc",ts:dateVal(x.fecha_subida||x.created_at),raw:x})).filter(x=>x.ts),tk=T.slice(0,20).map(x=>({kind:"ticket",ts:ticketDate(x),raw:x})).filter(x=>x.ts),all=[...base,...up,...tk].sort((a,b)=>b.ts-a.ts),seen=new Set(),out=[];for(const x of all){const r=x.raw||{},sig=x.kind==="bitacora"?`b|${r.accion||""}|${r.cliente_id||""}|${dayKey(x.ts)}`:x.kind==="doc"?`d|${r.cliente_id||""}|${r.nombre_archivo||""}|${dayKey(x.ts)}`:`t|${r.id||""}|${r.titulo||""}|${dayKey(x.ts)}`;if(seen.has(sig))continue;seen.add(sig);out.push(x);if(out.length>=LIM.activity)break}return out};
