const urgentItems=()=>T.filter(t=>isOpenTicket(t)&&ticketPri(t)>=2).sort((a,b)=>ticketPri(b)-ticketPri(a)||ticketDate(b)-ticketDate(a)).slice(0,LIM.urgent);
