let GLOBAL_NOTICE=null;async function loadGlobalNoticeAdmin(){try{const now=new Date().toISOString();const{data,error}=await s.from("avisos_globales").select("*").eq("activo",true).lte("inicio_publicacion",now).or(`fin_publicacion.is.null,fin_publicacion.gte.${now}`).order("inicio_publicacion",{ascending:false}).limit(1).maybeSingle();if(error)throw error;GLOBAL_NOTICE=data||null;$("#globalNoticeTitle")&&($("#globalNoticeTitle").value=data?.titulo||"");$("#globalNoticeMessage")&&($("#globalNoticeMessage").value=data?.mensaje||"");$("#globalNoticeSeverity")&&($("#globalNoticeSeverity").value=data?.severidad||"warn");$("#globalNoticeStatus")&&($("#globalNoticeStatus").textContent=data?`Activo: ${data.titulo}`:"Sin aviso activo.")}catch(err){console.warn("GLOBAL_NOTICE_LOAD_ERROR",err);$("#globalNoticeStatus")&&($("#globalNoticeStatus").textContent="No se pudo cargar el aviso global.")}}async function saveGlobalNotice(){const titulo=$("#globalNoticeTitle")?.value.trim(),mensaje=$("#globalNoticeMessage")?.value.trim(),severidad=$("#globalNoticeSeverity")?.value||"warn";if(!titulo)return toast("Falta el título del aviso.","warn");if(!mensaje)return toast("Falta el mensaje del aviso.","warn");const payload={titulo,mensaje,severidad,activo:true,mostrar_en_soporte:true,mostrar_en_dashboard:true,inicio_publicacion:new Date().toISOString(),fin_publicacion:null,creado_por:U?.id||null};try{if(GLOBAL_NOTICE?.id){const{error}=await s.from("avisos_globales").update(payload).eq("id",GLOBAL_NOTICE.id);if(error)throw error}else{const{error}=await s.from("avisos_globales").insert(payload);if(error)throw error}toast("Aviso global publicado.","ok");await loadGlobalNoticeAdmin()}catch(err){console.error("GLOBAL_NOTICE_SAVE_ERROR",err);toast(m(err),"bad")}}async function clearGlobalNotice(){try{if(GLOBAL_NOTICE?.id){const{error}=await s.from("avisos_globales").update({activo:false,fin_publicacion:new Date().toISOString()}).eq("id",GLOBAL_NOTICE.id);if(error)throw error}GLOBAL_NOTICE=null;$("#globalNoticeTitle")&&($("#globalNoticeTitle").value="");$("#globalNoticeMessage")&&($("#globalNoticeMessage").value="");$("#globalNoticeSeverity")&&($("#globalNoticeSeverity").value="warn");$("#globalNoticeStatus")&&($("#globalNoticeStatus").textContent="Sin aviso activo.");toast("Aviso global desactivado.","ok")}catch(err){console.error("GLOBAL_NOTICE_CLEAR_ERROR",err);toast(m(err),"bad")}}


const renderKPIs=()=>{const k=kpiData(),tone=heroTone(),openTrend=ticketTrend(T,7,"open"),urgentTrend=ticketTrend(T,7,"urgent");$("#kpiClientes")&&($("#kpiClientes").textContent=k.clientes);$("#kpiVigentes")&&($("#kpiVigentes").textContent=k.vigentes);$("#kpiPorVencer")&&($("#kpiPorVencer").textContent=k.porVencer);$("#kpiVencidos")&&($("#kpiVencidos").textContent=k.vencidos);$("#kpiTickets")&&($("#kpiTickets").textContent=k.ticketsAbiertos);$("#kpiUrgentes")&&($("#kpiUrgentes").textContent=k.urgentes);$("#polizasCountMini")&&($("#polizasCountMini").textContent=k.polizas);$("#criticalCount")&&($("#criticalCount").textContent=k.criticos);$(".dashboard-hero h1")&&($(".dashboard-hero h1").textContent="Vista operativa");$("#workSummary")&&($("#workSummary").textContent=tone.sub);setRailOpenCount(k.ticketsAbiertos);renderHeroMicro();applyRoleLayout();if(!$("#kpiTicketsSpark")&&$("#kpiTickets")?.parentElement)$("#kpiTickets").insertAdjacentHTML("afterend",`<div id="kpiTicketsSpark"></div>`);if(!$("#kpiUrgentesSpark")&&$("#kpiUrgentes")?.parentElement)$("#kpiUrgentes").insertAdjacentHTML("afterend",`<div id="kpiUrgentesSpark"></div>`);$("#kpiTicketsSpark")&&($("#kpiTicketsSpark").innerHTML=createSparkline(openTrend));$("#kpiUrgentesSpark")&&($("#kpiUrgentesSpark").innerHTML=createSparkline(urgentTrend));if(k.urgentes>LAST_URGENT_COUNT&&LAST_URGENT_COUNT!==0)flashUrgentKpi();LAST_URGENT_COUNT=k.urgentes};
const renderRadar=()=>{const items=radarItems();$("#radarCount")&&($("#radarCount").textContent=`${items.length} casos · últimos 14 días`);$("#radarList")&&($("#radarList").innerHTML=items.length?items.map(({c,urg,rec,ven,pv,score})=>`<div class="ops-item ${score>=14?"is-critical":score>=8?"is-hot":""}"><div class="ops-maincopy"><div class="ops-title"><a href="${clientUrl(c.id)}">${e(c.nombre||"Sin nombre")}</a></div><div class="ops-meta">${urg?`${urg} urgente(s)`:"Sin urgentes"} · ${rec?`${rec} reciente(s)`:"Sin actividad crítica reciente"}${isSalesRole()?` · ${ven?`${ven} vencido(s)`:"Sin vencidos"} · ${pv?`${pv} por vencer`:"Sin renovaciones cercanas"}`:" · Seguimiento de soporte"}</div><div class="ops-tags"><span class="tag ${score>=14?"bad":score>=8?"warn":"info"}">Score ${score}</span>${urg?`<span class="tag bad">Urgente</span>`:""}${isSalesRole()&&ven?`<span class="tag warn">Vencido</span>`:""}</div></div><div class="ops-score"><div class="score-ring ${score>=14?"bad":score>=8?"warn":"ok"}">${score}</div><div class="ops-actions row-actions"><button class="btn" data-act="focus" data-id="${c.id}">Cliente</button><button class="btn" data-act="ticket" data-id="${c.id}">Ticket</button></div></div></div>`).join(""):`<div class="empty-dash">${emptyCopy("radar")}</div>`)};
