const renderActivity=()=>{const items=activityItems();$("#activityCount")&&($("#activityCount").textContent=`${items.length} movimientos`);$("#activityList")&&($("#activityList").innerHTML=items.length?items.map(x=>{if(x.kind==="bitacora"){const r=x.raw,c=byId(C,r.cliente_id);return`<div class="activity-item"><div class="activity-dot"></div><div class="activity-copy"><div class="activity-title">${e(r.accion||"Actividad")}</div><div class="activity-meta">${c?`<a href="${clientUrl(c.id)}">${e(c.nombre)}</a> · `:""}${f(new Date(x.ts))}</div></div></div>`}if(x.kind==="doc"){const r=x.raw,c=byId(C,r.cliente_id);return`<div class="activity-item"><div class="activity-dot"></div><div class="activity-copy"><div class="activity-title">PDF subido</div><div class="activity-meta">${c?`<a href="${clientUrl(c.id)}">${e(c.nombre)}</a> · `:""}${e(r.nombre_archivo||"Documento")} · ${f(new Date(x.ts))}</div></div></div>`}const r=x.raw,c=byId(C,r.cliente_id);return`<div class="activity-item"><div class="activity-dot"></div><div class="activity-copy"><div class="activity-title">Ticket ${e(r.titulo||"sin título")}</div><div class="activity-meta">${c?`<a href="${clientUrl(c.id)}">${e(c.nombre)}</a> · `:""}${e(r.prioridad||"media")} · ${f(new Date(x.ts))}</div></div></div>`}).join(""):`<div class="empty-dash">${emptyCopy("activity")}</div>`)};
const renderRecentTickets=()=>{const items=recentTicketItems();$("#ticketsCount")&&($("#ticketsCount").textContent=`${items.length} tickets`);$("#ticketsList")&&($("#ticketsList").innerHTML=`<div class="batch-bar"><div class="batch-meta">${BATCH.tickets.size?`${BATCH.tickets.size} seleccionado(s)`:"Selecciona tickets para acción en lote"}</div><div class="batch-actions"><button class="btn" type="button" data-batch-close="tickets">Cerrar seleccionados</button><button class="btn" type="button" data-batch-clear="tickets">Limpiar</button></div></div>${items.length?items.map(t=>{const c=byId(C,t.cliente_id),prio=ticketPri(t)>=2?"bad":ticketPri(t)===1?"warn":"info",st=e(t.estado||t.status||"abierto"),checked=BATCH.tickets.has(String(t.id))?"checked":"";return`<div class="compact-item with-check ${ticketPri(t)>=2?"is-hot":""}"><label class="batch-check"><input type="checkbox" data-batch-item="tickets" data-id="${t.id}" ${checked}></label><div><div class="title"><a href="${ticketUrl(t.id)}">${e(t.titulo||"Ticket")}</a></div><div class="meta">${c?`<a href="${clientUrl(c.id)}">${e(c.nombre)}</a> · `:""}${e(t.prioridad||"media")} · ${st}</div></div><div class="tags"><span class="tag ${prio}">${e(t.prioridad||"media")}</span></div></div>`}).join(""):`<div class="empty-dash">${emptyCopy("tickets")}</div>`}`)};
