const renderUrgent=()=>{const items=urgentItems();$("#urgentCount")&&($("#urgentCount").textContent=items.length);$("#urgentList")&&($("#urgentList").innerHTML=`<div class="batch-bar"><div class="batch-meta">${BATCH.urgent.size?`${BATCH.urgent.size} seleccionado(s)`:"Selecciona tickets para acción en lote"}</div><div class="batch-actions"><button class="btn" type="button" data-batch-close="urgent">Cerrar seleccionados</button><button class="btn" type="button" data-batch-clear="urgent">Limpiar</button></div></div>${items.length?items.map(t=>{const c=byId(C,t.cliente_id),st=e(t.estado||t.status||"abierto"),checked=BATCH.urgent.has(String(t.id))?"checked":"";return`<div class="compact-item with-check is-critical"><label class="batch-check"><input type="checkbox" data-batch-item="urgent" data-id="${t.id}" ${checked}></label><div><div class="title"><a href="${ticketUrl(t.id)}">${e(t.titulo||"Ticket urgente")}</a></div><div class="meta">${c?`<a href="${clientUrl(c.id)}">${e(c.nombre)}</a> · `:""}${st}</div></div><div class="tags"><span class="tag bad">${e(t.prioridad||"urgente")}</span></div></div>`}).join(""):`<div class="empty-dash">${emptyCopy("urgent")}</div>`}`)};
