function renderAll(){const r=rows(),top=r.slice(0,LIM.crm);$("#resultsCount").textContent=`${r.length} cliente(s)`;$("#resultsList").innerHTML=top.length?top.map(({c,d,t})=>{const crit=clientCritico(c),last=latestDocOf(c.id),open=t.filter(isOpenTicket).length,boxCls=crit.on?"client-row is-critical":t.some(x=>isOpenTicket(x)&&ticketPri(x)>=2)?"client-row is-hot":"client-row";return`<div class="${boxCls}"><div class="client-main"><div class="client-name"><a href="${clientUrl(c.id)}">${e(c.nombre||"Sin nombre")}</a>${crit.on?` <span class="tag err">Crítico</span>`:""}</div><div class="client-sub">${[c.telefono,c.correo].filter(Boolean).map(e).join(" · ")||"Sin contacto"} · ${open} ticket(s) abierto(s)</div></div><div class="client-meta"><div class="client-sub">${crit.rec?`${crit.rec} en 7d · `:""}${crit.urg?`${crit.urg} urgente(s)`:""}${!crit.rec&&!crit.urg?"Seguimiento normal":""}</div><div class="ops-tags">${last?`<span class="tag info">${e(NICE[last.sistema_norm]||last.sistema||"PDF reciente")}</span>`:"<span class='tag'>Sin PDF reciente</span>"}</div></div><div class="client-actions row-actions"><button class="btn" data-act="focus" data-id="${c.id}">Cliente</button><button class="btn" data-act="ticket" data-id="${c.id}">Ticket</button><button class="btn" data-act="tickets_page" data-id="${c.id}">Tickets</button>${last?`<button class="btn" data-act="open" data-id="${last.id}">PDF</button>`:""}</div></div>`}).join(""):`<div class="empty-dash">${emptyCopy("results")}</div>`;renderBoards();renderPolizas();renderSearchSuggest()}
const needsManualReview=pdf=>!pdf?.serie||!pdf?.verificador;
const manualReviewReason=pdf=>[!pdf?.serie?"Serie no detectada":null,!pdf?.verificador?"Verificador no detectado":null].filter(Boolean).join(" · ");
async function upload(){if(!canUpload())return toast("Sin permisos para subir archivos.","bad");if(!FILES.length)return toast("Selecciona archivos primero.","warn");let clienteId=$("#clientSelect")?.value||CTX.clienteId||"";if(!clienteId){const q=prompt("Indica nombre o ID del cliente:");if(!q)return;const hit=findClient(q);if(!hit)return toast("Cliente no encontrado.","bad");clienteId=hit.id}const cli=byId(C,clienteId);if(!cli)return toast("Cliente inválido.","bad");const btn=$("#uploadBtn");if(btn)btn.disabled=true;toast(`Procesando ${FILES.length} archivo(s)...`);let ok=0,err=0,errors=[];try{for(const file of FILES){try{const pdf=await readPDF(file),path=`${clienteId}/${Date.now()}-${file.name.replace(/[^\w.\-]+/g,"_")}`,up=await s.storage.from("certificados").upload(path,file,{upsert:false,contentType:file.type||"application/pdf"});if(up.error)throw up.error;const requiresReview=needsManualReview(pdf);if(requiresReview){const go=confirm(`⚠️ ${file.name}\n\nSe detectó el sistema, pero faltan datos clave:\n${manualReviewReason(pdf)}\n\n¿Deseas subirlo de todas formas marcándolo para revisión manual?`);if(!go){err++;errors.push(`${file.name}: cancelado por revisión manual`);continue}}const ins=await s.from("documentos").insert({cliente_id:clienteId,nombre_archivo:file.name,nombre_archivo_norm:n(file.name),url_pdf:path,storage_path:path,tipo_documento:pdf.tipo||null,sistema:pdf.sistema||null,sistema_norm:pdf.sistema_norm||null,version_comercial:pdf.version||null,usuarios:pdf.usuarios||null,empresas_info:pdf.empresas||null,numero_serie:pdf.serie||null,verificador:pdf.verificador||null,empresa_certificado:pdf.empresa||null,inicio_vigencia:pdf.inicio||null,fin_vigencia:pdf.vigencia||null,fecha_fuente:pdf.vigencia||null,pdf_text:pdf.pdf_text||null,lectura_pdf_ok:true,lectura_pdf_error:null,requiere_revision:requiresReview,motivo_revision:requiresReview?manualReviewReason(pdf):null,subido_por:U?.id||null,tamano_bytes:file.size||null,mime_type:file.type||"application/pdf",origen_carga:"dashboard_upload",fecha_clasificacion:new Date().toISOString()}).select("*").single();if(ins.error)throw ins.error;D.unshift(ins.data);ok++;try{await la({accion:"documento_subido",documento_id:ins.data.id,cliente_id:clienteId,detalle:{archivo:file.name,sistema:pdf.sistema||null,revision:requiresReview}})}catch{}}catch(ex){console.error("UPLOAD_FILE_ERROR",file?.name,ex);err++;errors.push(`${file.name}: ${m(ex)}`)}}FILES=[];await load();if(ok&&err)toast(`Subidos ${ok}. Fallaron ${err}.`,"warn");else if(ok)toast(`${ok} archivo(s) subidos correctamente.`,"ok");else toast("No se pudo subir ningún archivo.","bad");if(errors.length)console.warn("UPLOAD_ERRORS",errors)}catch(ex){console.error("UPLOAD_ERROR",ex);toast(m(ex),"bad")}finally{if(btn)btn.disabled=false}}

