function ticketModal(clienteId,documentoId=null){const c=byId(C,clienteId);CTX={clienteId,documentoId};$("#ticketClienteNombre").value=c?.nombre||"";$("#ticketTitulo").value="";$("#ticketDescripcion").value="";$("#ticketTipo").value="Soporte";$("#ticketPrioridad").value="Media";$("#ticketStatus").textContent="Completa los datos.";$("#ticketOverlay")?.classList.add("open")}
async function saveTicketFn(){if(!CTX.clienteId) return $("#ticketStatus").textContent="Primero abre un cliente."; const titulo=$("#ticketTitulo").value.trim(); if(!titulo) return $("#ticketStatus").textContent="El título es obligatorio."; const {data,error}=await s.from("tickets").insert({cliente_id:CTX.clienteId,documento_id:CTX.documentoId,titulo,descripcion:$("#ticketDescripcion").value.trim(),tipo:$("#ticketTipo").value,prioridad:$("#ticketPrioridad").value,creado_por:U.id,origen:"dashboard"}).select("*").single(); if(error) return $("#ticketStatus").textContent=m(error); T.unshift(data); $("#ticketOverlay")?.classList.remove("open"); renderAll()}
const ISO=d=>new Date(d).toISOString(),DAYS_AGO=n=>{const d=new Date();d.setDate(d.getDate()-n);return ISO(d)},DASH_DOCS_FROM=()=>{const d=new Date();d.setMonth(d.getMonth()-3);return d.toISOString().slice(0,10)},DASH_TICKETS_FROM=()=>DAYS_AGO(60),TICKET_ACTIVE_STATES=["abierto","en_proceso","esperando_cliente","nuevo","pendiente"];async function loadActivity(){try{const a=await s.from("bitacora_view").select("*").order("fecha",{ascending:false}).limit(30);if(!a.error){A=a.data||[];return}const b=await s.from("bitacora").select("*").order("fecha",{ascending:false}).limit(30);A=b.data||[]}catch{A=[]}}async function load(){const docsFrom=DASH_DOCS_FROM(),ticketsFrom=DASH_TICKETS_FROM(),qClientes=s.from("clientes").select("*").order("nombre"),qDocs=s.from("documentos").select("*").eq("eliminado",false).or(`fin_vigencia.is.null,fin_vigencia.gte.${docsFrom}`).order("fecha_subida",{ascending:false}).limit(1200),qTickets=s.from("tickets").select("*,clientes(id,nombre)").or(`estado.in.(${TICKET_ACTIVE_STATES.join(",")}),fecha_actualizacion.gte.${ticketsFrom}`).order("fecha_actualizacion",{ascending:false}).limit(1200),[a,b,c]=await Promise.all([qClientes,qDocs,qTickets]);await loadActivity();if(a.error||b.error||c.error)throw(a.error||b.error||c.error);C=a.data||[];D=b.data||[];T=c.data||[];setGlobalSearchData({clientes:C,tickets:T});renderAll()}
const dayKey=v=>{const d=new Date(v||Date.now());return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`};
const lastNDays=n=>Array.from({length:n},(_,i)=>{const d=new Date();d.setDate(d.getDate()-(n-1-i));return dayKey(d)});
const createSparkline=(data=[])=>{if(!data.length)return"";const max=Math.max(...data),min=Math.min(...data),w=100,h=28,pts=data.map((v,i)=>{const x=data.length===1?w/2:i*(w/(data.length-1));const y=max===min?h/2:h-((v-min)/(max-min))*h;return`${x},${y}`}).join(" ");return`<svg class="kpi-spark" viewBox="0 0 100 28" preserveAspectRatio="none" aria-hidden="true"><polyline points="${pts}" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>`};
const ticketTrend=(items,days=7,mode="open")=>{const keys=lastNDays(days),map=new Map(keys.map(k=>[k,0]));items.forEach(t=>{const ts=ticketDate(t);if(!ts)return;const k=dayKey(ts);if(!map.has(k))return;if(mode==="urgent"&&ticketPri(t)<2)return;if(mode==="open"&&!isOpenTicket(t))return;map.set(k,(map.get(k)||0)+1)});return keys.map(k=>map.get(k)||0)};
const flashUrgentKpi=()=>{$("#kpiUrgentCard")?.classList.remove("kpi-flash");void $("#kpiUrgentCard")?.offsetWidth;$("#kpiUrgentCard")?.classList.add("kpi-flash");setTimeout(()=>$("#kpiUrgentCard")?.classList.remove("kpi-flash"),900)};
const toggleBatch=(bucket,id,on)=>{const set=bucket==="urgent"?BATCH.urgent:BATCH.tickets;on?set.add(String(id)):set.delete(String(id))};
const clearBatch=bucket=>{(bucket==="urgent"?BATCH.urgent:BATCH.tickets).clear();renderRecentTickets();renderUrgent()};
async function batchClose(bucket){const ids=[...(bucket==="urgent"?BATCH.urgent:BATCH.tickets)];if(!ids.length)return toast("No hay tickets seleccionados.","warn");if(!confirm(`Cerrar ${ids.length} ticket(s) seleccionado(s)?`))return;try{const now=new Date().toISOString(),{error}=await s.from("tickets").update({estado:"cerrado",fecha_actualizacion:now}).in("id",ids);if(error)throw error;T=T.map(t=>ids.includes(String(t.id))?{...t,estado:"cerrado",fecha_actualizacion:now}:t);clearBatch(bucket);renderAll();toast(`${ids.length} ticket(s) cerrados.`,"ok")}catch(err){console.error("BATCH_CLOSE_ERROR",err);toast(m(err),"bad")}};
function mergeTicketRow(row){const id=String(row.id),idx=T.findIndex(x=>String(x.id)===id);if(idx>=0)T[idx]={...T[idx],...row};else T.unshift(row)}
