function handleRealtimeTicket(payload){const row=payload?.new||payload?.old;if(!row?.id)return;if(payload.eventType==="DELETE"){T=T.filter(x=>String(x.id)!==String(row.id));renderAll();return}enrichTicketRow(row).then(full=>{mergeTicketRow(full);renderAll();if(payload.eventType==="INSERT"&&ticketPri(full)>=2){flashUrgentKpi();toast(`Nuevo ticket urgente: ${full.titulo||full.id}`,"warn")}})}
